actions.script:
platformTemplates = [:]
try {
    if (campaign.platformSettings) {
        def parsed = new groovy.json.JsonSlurper().parseText(campaign.platformSettings)
        parsed.each { key, value ->
            if (value instanceof Map && value.messageTemplate) {
                platformTemplates[key.toString().toLowerCase()] = value.messageTemplate
            }
        }
    }
} catch (Exception e) {
    platformTemplates = [:]
}

iterate.script:
def tmpl = platformTemplates[rcptPlatform.toLowerCase()] ?: (campaign.messageTemplate ?: '')
def autoContent = tmpl.replace('{name}', recipient.recipientName ?: '')
        .replace('{company}', recipient.recipientCompany ?: '')
        .replace('{title}', recipient.recipientTitle ?: '')
computedMessageContent = recipient.messageContent ? recipient.messageContent : autoContent
